from airflow.decorators import dag, task
from datetime import datetime

@dag(schedule='@daily', start_date=datetime(2024,1,1), catchup=False)
def my_dag():
    @task
    def extract(): return {'rows': 1000}

    @task
    def transform(data): return data['rows'] * 2

    @task
    def load(result): print(f'Loading {result} rows')

    data = extract()
    result = transform(data)
    load(result)

