from airflow.decorators import dag, task
from datetime import datetime
import requests

@dag(schedule='@daily', start_date=datetime(2024,1,1), catchup=False)
def etl_pipeline():

    @task
    def extract(date: str) -> dict:
        """Extract data from API"""
        response = requests.get(f'https://api.example.com/orders?date={date}')
        return response.json()  # Automatically pushed to XCom

    @task
    def transform(raw_data: dict) -> list:
        """Clean and transform data"""
        orders = raw_data['orders']
        return [
            {
                'order_id': o['id'],
                'amount': float(o['total']),
                'status': o['status'].lower()
            }
            for o in orders if o['status'] != 'cancelled'
        ]

    @task
    def load(clean_orders: list) -> int:
        """Load to database"""
        # Insert into DB...
        return len(clean_orders)

    @task
    def notify(row_count: int):
        print(f'Pipeline complete: {row_count} orders loaded')

    raw = extract('{{ ds }}')
    clean = transform(raw)
    count = load(clean)
    notify(count)

etl_pipeline()

