from airflow.decorators import dag, task
from datetime import datetime

@dag(schedule='@daily', start_date=datetime(2024,1,1), catchup=False)
def branching_pipeline():

    @task.branch
    def check_day(**context) -> str:
        day = context['execution_date'].weekday()
        return 'run_weekly' if day == 0 else 'run_daily'

    @task
    def run_daily(): print('Running daily job')

    @task
    def run_weekly(): print('Running weekly job')

    @task(trigger_rule='none_failed_min_one_success')
    def complete(): print('All done')

    branch = check_day()
    daily = run_daily()
    weekly = run_weekly()
    branch >> [daily, weekly] >> complete()

branching_pipeline()

from airflow.decorators import dag, task
from airflow.operators.bash import BashOperator
from airflow.providers.amazon.aws.sensors.s3 import S3KeySensor
from datetime import datetime

@dag(schedule='@daily', start_date=datetime(2024,1,1), catchup=False)
def mixed_pipeline():

    # Traditional sensor
    wait_for_file = S3KeySensor(
        task_id='wait_for_file',
        bucket_name='my-bucket',
        bucket_key='data/{{ ds }}/orders.csv',
        aws_conn_id='aws_default'
    )

    # Traditional bash operator
    validate = BashOperator(
        task_id='validate_file',
        bash_command='python /scripts/validate.py --date {{ ds }}'
    )

    # TaskFlow tasks
    @task
    def transform(**context):
        return {'date': context['ds'], 'rows': 1000}

    @task
    def load(data: dict):
        print(f"Loading {data['rows']} rows for {data['date']}")

    # Mix dependencies
    data = transform()
    wait_for_file >> validate >> data
    load(data)

mixed_pipeline()

