from airflow.models.xcom import BaseXCom
import json, boto3

class S3XComBackend(BaseXCom):
    PREFIX = 's3://my-bucket/xcom/'

    @staticmethod
    def serialize_value(value, **kwargs):
        if isinstance(value, (dict, list)) and len(str(value)) > 1000:
            key = f"xcom/{kwargs.get('dag_id')}/{kwargs.get('task_id')}/{kwargs.get('run_id')}.json"
            boto3.client('s3').put_object(Bucket='my-bucket', Key=key, Body=json.dumps(value))
            return BaseXCom.serialize_value(f's3://my-bucket/{key}')
        return BaseXCom.serialize_value(value)

