from airflow.hooks.base import BaseHook
import requests

class SlackWebhookHook(BaseHook):
    def __init__(self, slack_conn_id: str = 'slack_default'):
        super().__init__()
        self.slack_conn_id = slack_conn_id
        self._conn = None

    def get_conn(self):
        if self._conn is None:
            conn = self.get_connection(self.slack_conn_id)
            self._conn = conn.password  # Webhook URL stored in password field
        return self._conn

    def send_message(self, message: str, channel: str = '#data-alerts'):
        webhook_url = self.get_conn()
        payload = {'text': message, 'channel': channel}
        response = requests.post(webhook_url, json=payload)
        response.raise_for_status()
        return response.status_code

