from airflow.decorators import dag, task
from datetime import datetime

@dag(schedule='@daily', start_date=datetime(2024,1,1), catchup=False)
def dynamic_mapping_pipeline():

    @task
    def get_tables() -> list:
        # Returns list at runtime — could come from DB or API
        return ['orders', 'customers', 'products', 'inventory']

    @task
    def process_table(table_name: str) -> dict:
        print(f'Processing table: {table_name}')
        return {'table': table_name, 'rows': 1000}

    @task
    def summarize(results: list):
        print(f'All tables processed: {results}')

    tables = get_tables()
    # Creates one task instance per table at runtime
    results = process_table.expand(table_name=tables)
    summarize(results)  # receives list of all results

dynamic_mapping_pipeline()

