import pytest
from airflow.models import DagBag

@pytest.fixture
def dag_bag():
    return DagBag(dag_folder='dags/', include_examples=False)

def test_dag_loads_without_errors(dag_bag):
    assert len(dag_bag.import_errors) == 0, f'DAG import errors: {dag_bag.import_errors}'

def test_sales_pipeline_exists(dag_bag):
    dag = dag_bag.get_dag('sales_pipeline')
    assert dag is not None

def test_sales_pipeline_task_count(dag_bag):
    dag = dag_bag.get_dag('sales_pipeline')
    assert len(dag.tasks) == 5

def test_sales_pipeline_schedule(dag_bag):
    dag = dag_bag.get_dag('sales_pipeline')
    assert str(dag.schedule_interval) == '0 2 * * *'

def test_no_catchup(dag_bag):
    dag = dag_bag.get_dag('sales_pipeline')
    assert dag.catchup == False

def test_task_dependencies(dag_bag):
    dag = dag_bag.get_dag('sales_pipeline')
    extract   = dag.get_task('extract')
    transform = dag.get_task('transform')
    load      = dag.get_task('load')
    assert transform.task_id in [t.task_id for t in extract.downstream_list]
    assert load.task_id      in [t.task_id for t in transform.downstream_list]

def test_retries_configured(dag_bag):
    dag = dag_bag.get_dag('sales_pipeline')
    for task in dag.tasks:
        assert task.retries >= 1, f'Task {task.task_id} has no retries configured'

